local G = DYCLegendary local require = G.DYCModRequire local Spell = require( "dyc_spell" ) local DYCSpawnFX = require( "dyc_spawnfx" ) local CommonFns = require( "dyc_commonfns" ) local IsAliveOrNoHealth = CommonFns.IsAliveOrNoHealth local CanHit = CommonFns.CanHit local function TableContains(_table, _thing) for k, v in pairs(_table) do if v == _thing then return true end end return false end local function Launch(spell, caster, damage, p1, p2, p3, p4) damage = damage or spell.damage or 0x0 caster = caster or spell.caster local proj = SpawnPrefab( "dyc_projectile_lightning" ) proj.Transform:SetPosition(p1:Get()) local projectile = proj.components.projectile projectile:SetOnHitFn(function(proj, attacker, target, weapon) local rand = math.random() local shouldSummonLightning = rand < 0.2 local p = spell.dest local pos = proj:GetPosition() local isOnWater = proj.GetIsOnWater and proj:GetIsOnWater() if not isOnWater then local fxGround = SpawnPrefab( "dyc_fx_burntground_large" ) fxGround.Transform:SetPosition(pos.x, 0x0, pos.z) fxGround.Transform:SetRotation(math.random() * 0x168) end if shouldSummonLightning then SpawnPrefab( "lightning" ).Transform:SetPosition(pos.x, 0x0, pos.z) end local expo = SpawnPrefab( "dyc_fx_explode_blue_small" ) expo.Transform:SetPosition(pos.x, 0x0, pos.z) local randomScale = 0.9 + math.random() * 0.2 expo.Transform:SetScale(randomScale, randomScale, randomScale) local ents = TheSim:FindEntities(p.x, p.y, p.z, spell.aoe) for k, v in pairs(ents) do if CanHit(v, caster) then if IsAliveOrNoHealth(v) and shouldSummonLightning and spell.damageType == "fire" then if v.components.burnable and not v.components.fueled then v.components.burnable:Ignite() end end if IsAliveOrNoHealth(v) and v.components.combat then v.isNonAttDmg = true v.components.combat:GetAttacked(caster, damage, nil) v.isNonAttDmg = nil end if IsAliveOrNoHealth(v) and v.components.workable and v.components.workable.workleft > 0x0 then v.components.workable:WorkedBy(caster, 0x1) end if IsAliveOrNoHealth(v) and shouldSummonLightning and spell.damageType == "ice" then if v.components.freezable then v.components.freezable:AddColdness(spell.coldness or 0x1) v.components.freezable:SpawnShatterFX() end if v.components.burnable then if v.components.burnable:IsBurning() then v.components.burnable:Extinguish() elseif v.components.burnable.IsSmoldering and v.components.burnable:IsSmoldering() then v.components.burnable:SmotherSmolder() end end end end end proj:Remove() end) projectile:SetBezier3(p2, p3) projectile:SetBezierCalcDist(spell.bezierDist) projectile:SetSpeed(spell.speed) projectile:Throw(spell.weapon or caster, p4, caster) end local function onSetData(spell, data) data = data or {} spell.caster = data.caster spell.weapon = data.weapon spell.damage = data and data.damage or 0x14 spell.aoe = data and data.aoe or 0x3 spell.offsetY = data and data.offsetY or 1.5 spell.interval = data and data.interval or 0.2 spell.speed = data and data.speed or 0xa spell.number = data and data.number or 0xf spell.damageType = data and data.damageType or "regular" end local function onStopTask(spell, task) end local name = "clusterzaps" local SpellClass = Class(Spell, function(self, data) Spell._ctor(self, {name = name,}) local spell = self spell.onSetData = onSetData spell.onStopTask = onStopTask spell:SetData(data) spell.onCast = function(spell, target, p) local pos = spell.caster:GetPosition() local facingAngle = math.rad(spell.caster.Transform:GetRotation() + 0x5a) p = p or pos + Vector3(math.sin(facingAngle) * 0x3, 0x0, math.cos(facingAngle) * 0x3) spell.dest = p local timer, timerStrike, count = 0x0, 0x0, 0x0 local dirAngle = math.atan2(p.x - pos.x, p.z - pos.z) local GetUpAngle = function(count) local tmp = count % 0x6 local a = math.pi / 0xc return tmp == 0x1 and a * 0x5 or (tmp == 0x2 and a * 0x3) or (tmp == 0x3 and a * 0x1) or (tmp == 0x4 and - a * 0x1) or (tmp == 0x5 and - a * 0x3) or - a * 0x5 end local caster = spell.caster local damage = spell.damage local task = nil local frameInterval = spell.interval task = spell:StartTask(frameInterval, function() timer = timer + frameInterval spell.timer = timer timerStrike = timerStrike + frameInterval if count >= spell.number then spell:StopTask(task) else if timerStrike >= spell.interval then timerStrike = 0x0 count = count + 0x1 spell.count = count local r = math.max(spell.aoe - 1.8, 0x0) local a = math.random() * math.pi * 0x2 local p1 = caster:GetPosition() + Vector3(0x0, spell.offsetY, 0x0) local dir = (p - p1):GetNormalized() local dir2 = Vector3(math.sin(dirAngle + math.pi / 0x2), 0x0, math.cos(dirAngle + math.pi / 0x2)) local dirUp = Vector3(0x0, 0x1, 0x0) local aUp = GetUpAngle(count % 0x2 == 0x1 and (count + 0x1) / 0x2 or - count / 0x2) local rUp = 0x5 local p2 = p1 - dir * 0x5 + dirUp * 0x9 + dirUp * math.cos(aUp) * rUp + dir2 * math.sin(aUp) * rUp local p3 = (p + p2) / 0x2 + Vector3(0x0, 0x5, 0x0) local p4 = Vector3(p.x + r * math.sin(a), 0x0, p.z + r * math.cos(a)) spell.bezierDist = p1:Dist(p2) + p2:Dist(p4) Launch(spell, caster, damage, p1, p2, p3, p4) end end end) end end) SpellClass.name = name return SpellClass 